@'
:root {
    --uop-navy: #0d203a;
    --uop-royal: #123a6b;
    --uop-azure: #1c5fa8;
    --uop-gold: #d8a24a;
    --uop-cream: #f4f6fb;
    --uop-slate: #23374d;
}

* {
    box-sizing: border-box;
}

body {
    font-family: 'Montserrat', 'Source Sans 3', 'Segoe UI', sans-serif;
    margin: 0;
    background: linear-gradient(180deg, rgba(13, 32, 58, 0.04) 0%, rgba(241, 244, 250, 0.9) 120%);
    color: #1c2434;
    min-height: 100vh;
}

a {
    text-decoration: none;
}

a:hover, a:focus {
    text-decoration: none;
}

.site-header {
    background: linear-gradient(90deg, var(--uop-navy) 0%, var(--uop-royal) 65%, var(--uop-azure) 100%);
    color: #fff;
    position: sticky;
    top: 0;
    z-index: 1040;
}

.site-navbar {
    padding: 1rem 0;
}

.site-navbar .navbar-brand {
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: #fff;
}

.site-navbar .navbar-toggler {
    border-color: rgba(255, 255, 255, 0.3);
}

.site-navbar .navbar-nav .nav-link {
    color: rgba(255, 255, 255, 0.85);
    font-weight: 500;
    margin-left: 0.5rem;
    margin-right: 0.5rem;
    position: relative;
    padding-bottom: 0.3rem;
}

.site-navbar .navbar-nav .nav-link.active,
.site-navbar .navbar-nav .nav-link:hover {
    color: #fff;
}

.site-navbar .navbar-nav .nav-link.active::after,
.site-navbar .navbar-nav .nav-link:hover::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: -0.35rem;
    width: 100%;
    height: 3px;
    background: var(--uop-gold);
    border-radius: 6px;
}

.site-navbar .btn-outline-light {
    border-width: 2px;
    font-weight: 600;
    letter-spacing: 0.04em;
}

.layout-root {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

.site-main {
    flex: 1 0 auto;
    padding-top: 2rem;
    padding-bottom: 4rem;
}

.site-footer {
    background: var(--uop-navy);
    color: rgba(255, 255, 255, 0.82);
    padding: 2.5rem 0;
    flex-shrink: 0;
    font-size: 0.95rem;
}

.site-footer a {
    color: #fff;
}

.hero-section {
    position: relative;
    background: linear-gradient(115deg, rgba(18, 58, 107, 0.95) 0%, rgba(12, 30, 54, 0.92) 55%, rgba(28, 95, 168, 0.85) 100%);
    color: #fff;
    border-radius: 24px;
    overflow: hidden;
    padding: 4.5rem 3rem;
    margin-bottom: 3rem;
    box-shadow: 0 25px 45px rgba(15, 30, 54, 0.25);
}

.hero-section::after {
    content: '';
    position: absolute;
    inset: 15% -20% auto 55%;
    background: radial-gradient(circle at center, rgba(216, 162, 74, 0.45), transparent 55%);
    transform: rotate(-8deg);
}

.hero-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    background: rgba(255, 255, 255, 0.12);
    border-radius: 999px;
    padding: 0.4rem 1.1rem;
    font-size: 0.85rem;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    margin-bottom: 1.5rem;
}

.hero-title {
    font-size: clamp(2.4rem, 3vw, 3.25rem);
    font-weight: 700;
    line-height: 1.15;
    margin-bottom: 1.5rem;
}

.hero-lead {
    font-size: 1.15rem;
    max-width: 42rem;
    margin-bottom: 2rem;
}

.hero-cta .btn-primary {
    background-color: var(--uop-gold);
    border-color: var(--uop-gold);
    color: #1b2230;
    font-weight: 600;
    padding: 0.85rem 1.8rem;
    box-shadow: 0 18px 32px rgba(216, 162, 74, 0.35);
}

.hero-cta .btn-outline-light {
    border-color: rgba(255, 255, 255, 0.65);
    color: #fff;
    font-weight: 600;
}

.hero-cta .btn-outline-light:hover,
.hero-cta .btn-outline-light:focus {
    background: rgba(255, 255, 255, 0.18);
    border-color: rgba(255, 255, 255, 0.9);
}

.hero-metrics {
    margin-top: 3rem;
}

.metric-card {
    background: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.18);
    border-radius: 20px;
    padding: 1.25rem 1.5rem;
    backdrop-filter: blur(6px);
    min-height: 128px;
}

.metric-value {
    font-size: 2rem;
    font-weight: 700;
}

.metric-label {
    opacity: 0.85;
    font-weight: 500;
}

.section-heading {
    font-weight: 700;
    color: var(--uop-slate);
}

.quick-action-card,
.info-card,
.ticker-card {
    border-radius: 16px;
    border: none;
    box-shadow: 0 12px 24px rgba(15, 30, 54, 0.08);
    transition: transform 0.25s ease, box-shadow 0.25s ease;
}

.quick-action-card:hover,
.info-card:hover,
.ticker-card:hover {
    transform: translateY(-6px);
    box-shadow: 0 18px 38px rgba(15, 30, 54, 0.14);
}

.quick-action-card .card-title {
    color: var(--uop-royal);
    font-weight: 600;
}

.ticker-card {
    background: linear-gradient(145deg, rgba(18, 58, 107, 0.88), rgba(28, 95, 168, 0.88));
    color: #fff;
}

.ticker-card .list-group-item {
    background: transparent;
    color: #fff;
    border-color: rgba(255, 255, 255, 0.2);
}

.ticker-card .list-group-item strong {
    color: #ffe1a8;
}

.news-item-title {
    font-weight: 600;
    color: var(--uop-slate);
}

.highlight-tag {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    background: rgba(18, 58, 107, 0.08);
    color: var(--uop-royal);
    border-radius: 999px;
    padding: 0.35rem 0.85rem;
    font-size: 0.78rem;
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

.callout-panel {
    background: linear-gradient(120deg, rgba(13, 32, 58, 0.94) 0%, rgba(18, 58, 107, 0.92) 100%);
    border-radius: 24px;
    color: #fff;
    padding: 2.5rem;
    box-shadow: 0 24px 40px rgba(13, 32, 58, 0.35);
}

.callout-panel h3 {
    font-weight: 700;
}

.callout-panel .btn-light {
    color: var(--uop-royal);
    font-weight: 600;
    padding: 0.75rem 1.6rem;
}

.section-divider {
    height: 1px;
    background: linear-gradient(90deg, rgba(18, 58, 107, 0), rgba(18, 58, 107, 0.28), rgba(18, 58, 107, 0));
    margin: 3rem 0;
}

.card-icon {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: rgba(18, 58, 107, 0.12);
    color: var(--uop-royal);
    font-weight: 600;
}

@media (max-width: 991.98px) {
    .site-main {
        padding-top: 1.5rem;
    }

    .hero-section {
        padding: 3rem 2.25rem;
        text-align: center;
    }

    .hero-metrics {
        justify-content: center;
    }

    .hero-cta .btn {
        width: 100%;
        margin-bottom: 1rem;
    }

    .callout-panel {
        text-align: center;
    }
}

@media (max-width: 575.98px) {
    .hero-section {
        padding: 2.5rem 1.5rem;
    }

    .hero-title {
        font-size: 2.1rem;
    }
}
